// 构建next数组
vector<int> buildNext(const string& pattern) {
    int m = pattern.size();
    vector<int> next(m, 0);
    int j = 0;
    for (int i = 1; i < m; i++) {
        while (j > 0 && pattern[i] != pattern[j])
            j = next[j - 1];  // 回退
        if (pattern[i] == pattern[j])
            j++;
        next[i] = j;
    }
    return next;
}

// KMP匹配
int kmpSearch(const string& text, const string& pattern) {
    vector<int> next = buildNext(pattern);
    int j = 0;  // 模式串指针
    for (int i = 0; i < text.size(); i++) {
        while (j > 0 && text[i] != pattern[j])
            j = next[j - 1];  // 模式串回退，主串不回退
        if (text[i] == pattern[j])
            j++;
        if (j == pattern.size())
            return i - j + 1;  // 找到匹配
    }
    return -1;  // 未找到
}

struct TreeNode {
    int val;
    TreeNode *left, *right;
};

// 前序遍历（递归）
void preorder(TreeNode* root) {
    if (!root) return;
    cout << root->val << " ";
    preorder(root->left);
    preorder(root->right);
}

// 中序遍历（迭代）
void inorder(TreeNode* root) {
    stack<TreeNode*> stk;
    TreeNode* cur = root;
    while (cur || !stk.empty()) {
        while (cur) { stk.push(cur); cur = cur->left; }
        cur = stk.top(); stk.pop();
        cout << cur->val << " ";
        cur = cur->right;
    }
}

// 层序遍历（BFS）
void levelOrder(TreeNode* root) {
    queue<TreeNode*> q;
    if (root) q.push(root);
    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; i++) {
            TreeNode* node = q.front(); q.pop();
            cout << node->val << " ";
            if (node->left) q.push(node->left);
            if (node->right) q.push(node->right);
        }
    }
}

