// 简单内存池分配器
template<typename T>
class PoolAllocator {
    struct Block {
        char data[sizeof(T)];
        Block* next;
    };
    Block* freeList = nullptr;
public:
    using value_type = T;

    T* allocate(size_t n) {
        if (n == 1 && freeList) {
            Block* block = freeList;
            freeList = freeList->next;
            return reinterpret_cast<T*>(block);
        }
        return static_cast<T*>(::operator new(n * sizeof(T)));
    }

    void deallocate(T* p, size_t n) {
        if (n == 1) {
            Block* block = reinterpret_cast<Block*>(p);
            block->next = freeList;
            freeList = block;
        } else {
            ::operator delete(p);
        }
    }
};

