};

template<typename T>
concept HasSize = requires(T t) {
    { t.size() } -> std::integral;
};

// 组合Concepts
template<typename T>
concept Container = HasSize<T> && requires(T t) {
    { t.begin() } -> std::input_or_output_iterator;
    { t.end() } -> std::input_or_output_iterator;
};

// 使用Concept
