#include <iostream>
#include <vector>
#include <algorithm>
#include <functional>

int main() {
    int x = 10, y = 20;

    // 1. 基本Lambda
    auto basic = []() { std::cout << "Hello Lambda" << std::endl; };
    basic();

    // 2. 带参数和返回值
    auto add = [](int a, int b) -> int { return a + b; };
    std::cout << add(3, 4) << std::endl;  // 7

    // 3. 捕获方式
    // 值捕获（默认const，不可修改）
    auto capture_val = [=]() { return x + y; };

    // 引用捕获
    auto capture_ref = [&]() { x++; y++; return x + y; };

    // 混合捕获
    auto capture_mix = [x, &y]() { y++; return x + y; };

    // mutable：允许修改值捕获的变量
    auto mutable_lambda = [x]() mutable { x++; return x; };
    std::cout << mutable_lambda() << std::endl;  // 11
    std::cout << x << std::endl;                  // 10（原值不变）

    // 4. 泛型Lambda（C++14）
    auto generic = [](auto a, auto b) { return a + b; };
    std::cout << generic(1, 2) << std::endl;      // int
    std::cout << generic(1.5, 2.5) << std::endl;  // double

    // 5. 实际应用：STL算法
    std::vector<int> vec = {3, 1, 4, 1, 5, 9};

    // 排序
    std::sort(vec.begin(), vec.end(), [](int a, int b) {
        return a > b;  // 降序
    });

    // 查找
    auto it = std::find_if(vec.begin(), vec.end(), [](int n) {
        return n > 4;
    });

    // 6. 存储在std::function中
    std::function<int(int, int)> func = [](int a, int b) {
        return a * b;
    };

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <utility>

class MyString {
    char* data;
    size_t len;
public:
    // 构造函数
    MyString(const char* str) {
        len = strlen(str);
        data = new char[len + 1];
        strcpy(data, str);
        std::cout << "Constructor: " << data << std::endl;
    }

    // 拷贝构造函数（深拷贝）
    MyString(const MyString& other) {
        len = other.len;
        data = new char[len + 1];
        strcpy(data, other.data);
        std::cout << "Copy Constructor: " << data << std::endl;
    }

    // 移动构造函数（转移资源）
    MyString(MyString&& other) noexcept {
        data = other.data;   // 窃取指针
        len = other.len;
        other.data = nullptr; // 置空源对象
        other.len = 0;
        std::cout << "Move Constructor: " << data << std::endl;
    }

    // 拷贝赋值
    MyString& operator=(const MyString& other) {
        if (this != &other) {
            delete[] data;
            len = other.len;
            data = new char[len + 1];
            strcpy(data, other.data);
        }
        std::cout << "Copy Assignment" << std::endl;
        return *this;
    }

    // 移动赋值
    MyString& operator=(MyString&& other) noexcept {
        if (this != &other) {
            delete[] data;
            data = other.data;
            len = other.len;
            other.data = nullptr;
            other.len = 0;
        }
        std::cout << "Move Assignment" << std::endl;
        return *this;
    }

    ~MyString() {
        if (data) {
            std::cout << "Destructor: " << data << std::endl;
            delete[] data;
        }
    }
};

