// 异常安全示例
class Resource {
    int* data;
public:
    Resource() : data(new int[100]) {
        std::cout << "Resource acquired" << std::endl;
    }

    ~Resource() {
        delete[] data;
        std::cout << "Resource released" << std::endl;
    }

    // 移动操作标记为noexcept
    Resource(Resource&& other) noexcept : data(other.data) {
        other.data = nullptr;
    }

    Resource& operator=(Resource&& other) noexcept {
        if (this != &other) {
            delete[] data;
            data = other.data;
            other.data = nullptr;
        }
        return *this;
    }
};

void risky_function(bool should_throw) {
    Resource r;  // RAII保证资源释放
    if (should_throw) {
        throw MyException("Something went wrong");
    }
}

int main() {
    // 基本异常处理
    try {
        risky_function(true);
    } catch (const MyException& e) {
        std::cout << "Caught: " << e.what() << std::endl;
    } catch (const std::exception& e) {
        std::cout << "Standard exception: " << e.what() << std::endl;
    } catch (...) {
        std::cout << "Unknown exception" << std::endl;
    }

    // noexcept检查
    std::cout << "safe_function is noexcept: " << noexcept(safe_function()) << std::endl;

    return 0;
}

#include <iostream>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <atomic>
#include <future>
#include <vector>

std::mutex mtx;
std::condition_variable cv;
bool ready = false;

// 基本线程函数
void worker(int id) {
    std::unique_lock<std::mutex> lock(mtx);
    cv.wait(lock, []{ return ready; });  // 等待条件

    std::cout << "Worker " << id << " is processing" << std::endl;
}

// 原子变量（无锁计数器）
std::atomic<int> counter{0};

void increment() {
    for (int i = 0; i < 1000; ++i) {
        counter.fetch_add(1, std::memory_order_relaxed);
    }
}

// async异步任务
int compute(int x) {
    std::this_thread::sleep_for(std::chrono::seconds(1));
    return x * x;
}

int main() {
    // 1. 创建线程
    std::vector<std::thread> threads;
    for (int i = 0; i < 5; ++i) {
        threads.emplace_back(worker, i);
    }

    // 2. 通知所有线程开始
    {
        std::lock_guard<std::mutex> lock(mtx);
        ready = true;
    }
    cv.notify_all();

    // 3. 等待线程完成
    for (auto& t : threads) {
        t.join();
    }

    // 4. 原子操作测试
    std::thread t1(increment);
    std::thread t2(increment);
    t1.join();
    t2.join();
    std::cout << "Counter: " << counter << std::endl;  // 2000

    // 5. async异步调用
    std::future<int> result = std::async(std::launch::async, compute, 5);
    std::cout << "Computing..." << std::endl;
    std::cout << "Result: " << result.get() << std::endl;  // 25

    // 6. 死锁避免
    std::mutex m1, m2;
    {
        std::lock(m1, m2);  // 同时获取多个锁
        std::lock_guard<std::mutex> lock1(m1, std::adopt_lock);
        std::lock_guard<std::mutex> lock2(m2, std::adopt_lock);
        // 安全使用两个锁
    }

    return 0;
}

